import { useState, useEffect, useRef } from 'react'
import { FolderPlus } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Collection } from '../api/client'
import CollectionList from './CollectionList'

interface AddToCollectionDropdownProps {
  recipeId: number
  onCreateNew: () => void
}

export default function AddToCollectionDropdown({
  recipeId,
  onCreateNew,
}: AddToCollectionDropdownProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [collections, setCollections] = useState<Collection[]>([])
  const [loading, setLoading] = useState(false)
  const [addingTo, setAddingTo] = useState<number | null>(null)
  const dropdownRef = useRef<HTMLDivElement>(null)

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setIsOpen(false)
      }
    }

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [isOpen])

  // Load collections when dropdown opens
  useEffect(() => {
    if (!isOpen) return
    let cancelled = false
    ;(async () => {
      setLoading(true)
      try {
        const data = await api.collections.list()
        if (!cancelled) setCollections(data)
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load collections:', error)
          toast.error('Failed to load collections')
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [isOpen])

  const handleAddToCollection = async (collectionId: number) => {
    setAddingTo(collectionId)
    try {
      await api.collections.addRecipe(collectionId, recipeId)
      const collection = collections.find((c) => c.id === collectionId)
      toast.success(`Added to ${collection?.name || 'collection'}`)
      setIsOpen(false)
    } catch (error: unknown) {
      if (error instanceof Error && error.message.includes('already')) {
        toast.info('Recipe is already in this collection')
      } else {
        console.error('Failed to add to collection:', error)
        toast.error('Failed to add to collection')
      }
    } finally {
      setAddingTo(null)
    }
  }

  const handleCreateNew = () => {
    setIsOpen(false)
    onCreateNew()
  }

  return (
    <div ref={dropdownRef} className="relative">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="rounded-full bg-black/40 p-2 text-white backdrop-blur-sm transition-colors hover:text-primary"
        title="Add to collection"
      >
        <FolderPlus className="h-5 w-5" />
      </button>

      {isOpen && (
        <div className="absolute right-0 top-full z-50 mt-2 w-56 rounded-lg border border-border bg-card shadow-lg">
          <div className="p-2">
            <h3 className="mb-2 px-2 text-xs font-medium uppercase tracking-wider text-muted-foreground">
              Add to Collection
            </h3>
            <CollectionList
              collections={collections}
              loading={loading}
              addingTo={addingTo}
              onAdd={handleAddToCollection}
              onCreateNew={handleCreateNew}
            />
          </div>
        </div>
      )}
    </div>
  )
}

import { FolderPlus, Plus } from 'lucide-react'
import type { Collection } from '../api/client'
import { cn } from '../lib/utils'

interface CollectionListProps {
  collections: Collection[]
  loading: boolean
  addingTo: number | null
  onAdd: (collectionId: number) => void
  onCreateNew: () => void
}

export default function CollectionList({
  collections,
  loading,
  addingTo,
  onAdd,
  onCreateNew,
}: CollectionListProps) {
  if (loading) {
    return (
      <div className="px-2 py-4 text-center text-sm text-muted-foreground">
        Loading...
      </div>
    )
  }

  return (
    <>
      {collections.length > 0 ? (
        <div className="max-h-48 overflow-y-auto">
          {collections.map((collection) => (
            <button
              key={collection.id}
              onClick={() => onAdd(collection.id)}
              disabled={addingTo === collection.id}
              className={cn(
                'flex w-full items-center gap-2 rounded-md px-2 py-2 text-left text-sm transition-colors',
                'text-foreground hover:bg-muted disabled:opacity-50'
              )}
            >
              <FolderPlus className="h-4 w-4 text-muted-foreground" />
              <span className="flex-1 truncate">{collection.name}</span>
              {addingTo === collection.id && (
                <span className="text-xs text-muted-foreground">Adding...</span>
              )}
            </button>
          ))}
        </div>
      ) : (
        <div className="px-2 py-2 text-sm text-muted-foreground">
          No collections yet
        </div>
      )}

      <div className="mt-1 border-t border-border pt-1">
        <button
          onClick={onCreateNew}
          className="flex w-full items-center gap-2 rounded-md px-2 py-2 text-left text-sm text-primary transition-colors hover:bg-muted"
        >
          <Plus className="h-4 w-4" />
          Create New Collection
        </button>
      </div>
    </>
  )
}

import { useState, FormEvent } from 'react'
import { api } from '../api/client'

export default function DeviceCodeEntry() {
  const [code, setCode] = useState('')
  const [error, setError] = useState('')
  const [success, setSuccess] = useState(false)
  const [submitting, setSubmitting] = useState(false)

  async function handleSubmit(e: FormEvent) {
    e.preventDefault()
    setError('')
    setSubmitting(true)

    try {
      await api.device.authorize(code)
      setSuccess(true)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Authorization failed')
    } finally {
      setSubmitting(false)
    }
  }

  if (success) {
    return (
      <div className="rounded-md bg-green-50 p-4 text-center text-sm text-green-800 dark:bg-green-900/20 dark:text-green-300">
        Device authorized successfully! The other device should now be connected.
      </div>
    )
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {error && (
        <div role="alert" className="rounded-md bg-red-50 p-3 text-sm text-red-800 dark:bg-red-900/20 dark:text-red-300">
          {error}
        </div>
      )}

      <div>
        <label htmlFor="device-code" className="block text-sm font-medium text-foreground">
          Enter the code shown on the other device
        </label>
        <input
          id="device-code"
          type="text"
          maxLength={6}
          required
          autoComplete="off"
          value={code}
          onChange={(e) => setCode(e.target.value.toUpperCase())}
          placeholder="ABC123"
          className="mt-1 block w-full rounded-md border border-input bg-background px-3 py-2 text-center font-mono text-2xl tracking-widest text-foreground shadow-sm focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
      </div>

      <button
        type="submit"
        disabled={submitting || code.length < 6}
        className="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground shadow-sm hover:bg-primary/90 disabled:opacity-50"
      >
        {submitting ? 'Authorizing...' : 'Authorize Device'}
      </button>
    </form>
  )
}

import { Component, type ReactNode, type ErrorInfo } from 'react'
import { AlertTriangle, RefreshCw } from 'lucide-react'

interface Props {
  children: ReactNode
  fallback?: ReactNode
}

interface State {
  hasError: boolean
  error: Error | null
  errorInfo: ErrorInfo | null
}

/**
 * Error boundary component that catches JavaScript errors in child components.
 *
 * Displays a user-friendly error UI instead of crashing the entire app.
 * Users can click "Try Again" to reset the error state and remount children.
 *
 * @example
 * <ErrorBoundary>
 *   <App />
 * </ErrorBoundary>
 *
 * // Or with custom fallback
 * <ErrorBoundary fallback={<CustomErrorUI />}>
 *   <App />
 * </ErrorBoundary>
 */
export default class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props)
    this.state = { hasError: false, error: null, errorInfo: null }
  }

  static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    this.setState({ errorInfo })

    // Log error for debugging
    console.error('ErrorBoundary caught an error:', error, errorInfo)
  }

  handleReset = (): void => {
    this.setState({ hasError: false, error: null, errorInfo: null })
  }

  render(): ReactNode {
    const { hasError, error } = this.state
    const { children, fallback } = this.props

    if (hasError) {
      // Use custom fallback if provided
      if (fallback) {
        return fallback
      }

      // Default error UI
      return (
        <div className="flex min-h-screen flex-col items-center justify-center bg-background p-4">
          <div className="w-full max-w-md rounded-xl border border-border bg-card p-8 text-center shadow-lg">
            {/* Icon */}
            <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-destructive/10">
              <AlertTriangle className="h-8 w-8 text-destructive" />
            </div>

            {/* Title */}
            <h1 className="mb-2 text-xl font-semibold text-foreground">
              Something went wrong
            </h1>

            {/* Description */}
            <p className="mb-6 text-sm text-muted-foreground">
              An unexpected error occurred. This has been logged for debugging.
            </p>

            {/* Error details (development only) */}
            {import.meta.env.DEV && error && (
              <div className="mb-6 rounded-lg bg-muted p-3 text-left">
                <p className="mb-1 text-xs font-medium text-muted-foreground">
                  Error Details
                </p>
                <code className="text-xs text-destructive">
                  {error.name}: {error.message}
                </code>
              </div>
            )}

            {/* Actions */}
            <div className="flex flex-col gap-2">
              <button
                onClick={this.handleReset}
                className="flex w-full items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2.5 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
              >
                <RefreshCw className="h-4 w-4" />
                Try Again
              </button>

              <button
                onClick={() => window.location.reload()}
                className="w-full rounded-lg bg-muted px-4 py-2.5 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted/80 hover:text-foreground"
              >
                Reload Page
              </button>
            </div>
          </div>
        </div>
      )
    }

    return children
  }
}

import { useNavigate, useLocation } from 'react-router-dom'
import { Moon, Sun, Home, Heart, BookOpen, FolderOpen, Settings } from 'lucide-react'
import { useProfile } from '../contexts/ProfileContext'
import { useMode } from '../router'
import ProfileDropdown from './ProfileDropdown'

const NAV_BASE = 'rounded-lg p-1.5 transition-colors'
const NAV_INACTIVE = `${NAV_BASE} text-muted-foreground hover:bg-muted hover:text-primary`
const NAV_ACTIVE = `${NAV_BASE} bg-muted text-primary`

export default function NavHeader() {
  const navigate = useNavigate()
  const location = useLocation()
  const mode = useMode()
  const { profile, theme, toggleTheme, logout } = useProfile()

  const isActive = (path: string) => location.pathname === path
    || (path !== '/home' && location.pathname.startsWith(path))

  const handleLogout = () => {
    logout()
    navigate('/')
  }

  if (!profile) return null

  return (
    <header className="flex items-center justify-between border-b border-border px-4 py-3">
      <button
        onClick={() => navigate('/home')}
        className="text-xl font-medium text-primary hover:opacity-80 transition-opacity"
      >
        Cookie
      </button>

      <div className="flex items-center gap-1">
        {/* Home */}
        <button
          onClick={() => navigate('/home')}
          className={isActive('/home') ? NAV_ACTIVE : NAV_INACTIVE}
          aria-label="Home"
          aria-current={isActive('/home') ? 'page' : undefined}
        >
          <Home className="h-5 w-5" />
        </button>

        {/* All Recipes */}
        <button
          onClick={() => navigate('/all-recipes')}
          className={isActive('/all-recipes') ? NAV_ACTIVE : NAV_INACTIVE}
          aria-label="All recipes"
          aria-current={isActive('/all-recipes') ? 'page' : undefined}
        >
          <BookOpen className="h-5 w-5" />
        </button>

        {/* Favorites */}
        <button
          onClick={() => navigate('/favorites')}
          className={isActive('/favorites') ? `${NAV_BASE} bg-muted text-accent` : `${NAV_BASE} text-muted-foreground hover:bg-muted hover:text-accent`}
          aria-label="View favorites"
          aria-current={isActive('/favorites') ? 'page' : undefined}
        >
          <Heart className="h-5 w-5" />
        </button>

        {/* Collections */}
        <button
          onClick={() => navigate('/collections')}
          className={isActive('/collections') || isActive('/collection') ? NAV_ACTIVE : NAV_INACTIVE}
          aria-label="View collections"
          aria-current={isActive('/collections') || isActive('/collection') ? 'page' : undefined}
        >
          <FolderOpen className="h-5 w-5" />
        </button>

        {/* Theme toggle */}
        <button
          onClick={toggleTheme}
          className={`${NAV_BASE} text-muted-foreground hover:bg-muted hover:text-foreground`}
          aria-label={theme === 'light' ? 'Switch to dark mode' : 'Switch to light mode'}
        >
          {theme === 'light' ? (
            <Moon className="h-5 w-5" />
          ) : (
            <Sun className="h-5 w-5" />
          )}
        </button>

        {/* Settings */}
        <button
          onClick={() => navigate('/settings')}
          className={isActive('/settings') ? NAV_ACTIVE : NAV_INACTIVE}
          aria-label="Settings"
          aria-current={isActive('/settings') ? 'page' : undefined}
        >
          <Settings className="h-5 w-5" />
        </button>

        {/* Profile avatar with dropdown */}
        <ProfileDropdown
          profileName={profile.name}
          avatarColor={profile.avatar_color}
          mode={mode}
          onLogout={handleLogout}
        />
      </div>
    </header>
  )
}

import { useState, useEffect } from 'react'
import { X, Sparkles, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { api, type RecipeDetail } from '../api/client'
import { cn, handleQuotaError } from '../lib/utils'
import { useAIStatus } from '../contexts/AIStatusContext'
import SuggestionSelector from './SuggestionSelector'
import CustomRemixInput from './CustomRemixInput'

interface RemixModalProps {
  recipe: RecipeDetail
  profileId: number
  isOpen: boolean
  onClose: () => void
  onRemixCreated: (recipeId: number) => void
}

interface RemixHeaderProps {
  onClose: () => void
  disabled: boolean
}

function RemixHeader({ onClose, disabled }: RemixHeaderProps) {
  return (
    <div className="flex items-center justify-between border-b border-border px-6 py-4">
      <div className="flex items-center gap-2">
        <Sparkles className="h-5 w-5 text-primary" />
        <h2 className="text-lg font-semibold text-foreground">Remix This Recipe</h2>
      </div>
      <button
        onClick={onClose}
        disabled={disabled}
        className="rounded-full p-1 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
      >
        <X className="h-5 w-5" />
      </button>
    </div>
  )
}

interface RemixCreateButtonProps {
  creating: boolean
  enabled: boolean
  onClick: () => void
}

function RemixCreateButton({ creating, enabled, onClick }: RemixCreateButtonProps) {
  return (
    <button
      onClick={onClick}
      disabled={!enabled}
      className={cn(
        'flex w-full items-center justify-center gap-2 rounded-lg px-4 py-3 text-sm font-medium transition-colors',
        enabled
          ? 'bg-primary text-primary-foreground hover:bg-primary/90'
          : 'bg-muted text-muted-foreground cursor-not-allowed'
      )}
    >
      {creating ? (
        <>
          <Loader2 className="h-4 w-4 animate-spin" />
          Creating Remix...
        </>
      ) : (
        <>
          <Sparkles className="h-4 w-4" />
          Create Remix
        </>
      )}
    </button>
  )
}

function toggleSuggestion(
  prev: string[],
  suggestion: string,
  clearCustom: () => void
): string[] {
  if (prev.includes(suggestion)) {
    return prev.filter((s) => s !== suggestion)
  }
  if (prev.length >= 4) {
    toast.info('You can select up to 4 modifications')
    return prev
  }
  clearCustom()
  return [...prev, suggestion]
}

function getModification(customInput: string, selectedSuggestions: string[]): string | null {
  if (customInput.trim()) return customInput.trim()
  if (selectedSuggestions.length === 1) return selectedSuggestions[0]
  if (selectedSuggestions.length > 1) return selectedSuggestions.join(' AND ')
  return null
}

export default function RemixModal({
  recipe,
  profileId,
  isOpen,
  onClose,
  onRemixCreated,
}: RemixModalProps) {
  const { setFeatureQuotaExhausted } = useAIStatus()
  const [suggestions, setSuggestions] = useState<string[]>([])
  const [loadingSuggestions, setLoadingSuggestions] = useState(false)
  const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([])
  const [customInput, setCustomInput] = useState('')
  const [creating, setCreating] = useState(false)

  // Load suggestions when modal opens
  useEffect(() => {
    if (!isOpen) return
    let cancelled = false
    ;(async () => {
      setSuggestions([])
      setSelectedSuggestions([])
      setCustomInput('')
      setLoadingSuggestions(true)
      try {
        const response = await api.ai.remix.getSuggestions(recipe.id)
        if (!cancelled) setSuggestions(response.suggestions)
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load remix suggestions:', error)
          if (handleQuotaError(error, 'Failed to load suggestions')) {
            setFeatureQuotaExhausted('remix')
          }
        }
      } finally {
        if (!cancelled) setLoadingSuggestions(false)
      }
    })()
    return () => { cancelled = true }
  }, [isOpen, recipe.id, setFeatureQuotaExhausted])

  const handleSuggestionClick = (suggestion: string) => {
    setSelectedSuggestions((prev) =>
      toggleSuggestion(prev, suggestion, () => setCustomInput(''))
    )
  }

  const handleCustomInputChange = (value: string) => {
    setCustomInput(value)
    if (value.trim()) setSelectedSuggestions([])
  }

  const canSubmit = !creating && (selectedSuggestions.length > 0 || customInput.trim() !== '')

  const handleCreateRemix = async () => {
    const modification = getModification(customInput, selectedSuggestions)
    if (!modification) return
    setCreating(true)
    try {
      const remix = await api.ai.remix.create(recipe.id, modification, profileId)
      toast.success(`Created "${remix.title}"`)
      onRemixCreated(remix.id)
      onClose()
    } catch (error) {
      console.error('Failed to create remix:', error)
      if (handleQuotaError(error, 'Failed to create remix')) {
        setFeatureQuotaExhausted('remix')
        onClose()
      }
    } finally {
      setCreating(false)
    }
  }

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4">
      <div className="relative w-full max-w-md rounded-xl bg-card shadow-2xl">
        <RemixHeader onClose={onClose} disabled={creating} />
        <div className="px-6 py-5">
          <p className="mb-4 text-sm text-muted-foreground">
            Choose one or more modifications, or describe your own remix of "{recipe.title}"
          </p>
          <SuggestionSelector
            suggestions={suggestions}
            selectedSuggestions={selectedSuggestions}
            loadingSuggestions={loadingSuggestions}
            disabled={creating}
            onSuggestionClick={handleSuggestionClick}
          />
          <CustomRemixInput
            value={customInput}
            onChange={handleCustomInputChange}
            disabled={creating}
          />
          <RemixCreateButton creating={creating} enabled={canSubmit} onClick={handleCreateRemix} />
        </div>
      </div>
    </div>
  )
}

/**
 * Skeleton loading components for React frontend
 * Used to show placeholder content while data is loading
 */

import { cn } from '../lib/utils'

/**
 * Base skeleton element with pulse animation
 */
function Skeleton({ className }: { className?: string }) {
  return (
    <div className={cn('animate-pulse rounded bg-muted', className)} />
  )
}

/**
 * Skeleton for recipe cards in grids (AllRecipes, Search, Favorites)
 */
export function RecipeCardSkeleton() {
  return (
    <div className="overflow-hidden rounded-lg bg-card shadow-sm">
      {/* Image placeholder */}
      <Skeleton className="aspect-[4/3] rounded-none" />
      {/* Content */}
      <div className="p-3 space-y-2">
        {/* Title */}
        <Skeleton className="h-4 w-3/4" />
        {/* Meta row */}
        <div className="flex items-center gap-3">
          <Skeleton className="h-3 w-16" />
          <Skeleton className="h-3 w-12" />
        </div>
      </div>
    </div>
  )
}

/**
 * Grid of recipe card skeletons
 */
export function RecipeGridSkeleton({ count = 8 }: { count?: number }) {
  return (
    <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4">
      {Array.from({ length: count }).map((_, i) => (
        <RecipeCardSkeleton key={i} />
      ))}
    </div>
  )
}

/**
 * Skeleton for collection cards
 */
export function CollectionCardSkeleton() {
  return (
    <div className="overflow-hidden rounded-lg bg-card p-4 shadow-sm">
      {/* Icon placeholder */}
      <Skeleton className="mb-8 h-12 w-12 rounded-lg" />
      {/* Name */}
      <Skeleton className="mb-2 h-5 w-3/4" />
      {/* Count */}
      <Skeleton className="h-4 w-16" />
    </div>
  )
}

/**
 * Grid of collection card skeletons
 */
export function CollectionGridSkeleton({ count = 8 }: { count?: number }) {
  return (
    <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4">
      {Array.from({ length: count }).map((_, i) => (
        <CollectionCardSkeleton key={i} />
      ))}
    </div>
  )
}

/**
 * Full recipe detail page skeleton
 */
export function RecipeDetailSkeleton() {
  return (
    <div className="min-h-screen bg-background">
      {/* Hero image skeleton */}
      <div className="relative h-64 sm:h-80">
        <Skeleton className="h-full w-full rounded-none" />
        {/* Back button placeholder */}
        <div className="absolute left-4 top-4">
          <Skeleton className="h-10 w-10 rounded-full" />
        </div>
        {/* Title overlay placeholder */}
        <div className="absolute bottom-4 left-4 right-4">
          <Skeleton className="mb-2 h-7 w-3/4" />
          <div className="flex gap-3">
            <Skeleton className="h-4 w-16" />
            <Skeleton className="h-4 w-24" />
          </div>
        </div>
        {/* Action buttons placeholder */}
        <div className="absolute bottom-4 right-4 flex gap-2">
          <Skeleton className="h-10 w-10 rounded-full" />
          <Skeleton className="h-10 w-10 rounded-full" />
          <Skeleton className="h-10 w-20 rounded-full" />
        </div>
      </div>

      {/* Meta info skeleton */}
      <div className="border-b border-border px-4 py-4">
        <div className="flex flex-wrap gap-4">
          <Skeleton className="h-5 w-24" />
          <Skeleton className="h-5 w-24" />
          <Skeleton className="h-5 w-24" />
          <Skeleton className="h-5 w-32" />
        </div>
      </div>

      {/* Tabs skeleton */}
      <div className="border-b border-border px-4">
        <div className="flex gap-4 py-3">
          <Skeleton className="h-5 w-20" />
          <Skeleton className="h-5 w-20" />
          <Skeleton className="h-5 w-16" />
          <Skeleton className="h-5 w-12" />
        </div>
      </div>

      {/* Content skeleton */}
      <div className="px-4 py-6 space-y-4">
        {Array.from({ length: 6 }).map((_, i) => (
          <div key={i} className="flex items-start gap-3">
            <Skeleton className="h-7 w-7 rounded-full shrink-0" />
            <Skeleton className="h-5 flex-1" />
          </div>
