import { useState, useEffect } from 'react'
import { Loader2, Save } from 'lucide-react'
import { toast } from 'sonner'
import { api, type QuotaResponse, type QuotaLimits } from '../../api/client'

const FEATURE_LABELS: { key: keyof QuotaLimits; label: string }[] = [
  { key: 'remix', label: 'Remixes' },
  { key: 'remix_suggestions', label: 'Remix Suggestions' },
  { key: 'scale', label: 'Scaling' },
  { key: 'tips', label: 'Tips' },
  { key: 'discover', label: 'Discover' },
  { key: 'timer', label: 'Timer Naming' },
]

interface AIQuotaSectionProps {
  quotaData: QuotaResponse | null
  onSave: (limits: QuotaLimits) => void
}

export default function AIQuotaSection({ quotaData, onSave }: AIQuotaSectionProps) {
  const defaultLimits: QuotaLimits = { remix: 0, remix_suggestions: 0, scale: 0, tips: 0, discover: 0, timer: 0 }
  const [limits, setLimits] = useState<QuotaLimits>(
    quotaData?.limits ?? defaultLimits,
  )
  const [saving, setSaving] = useState(false)

  // Sync limits when quotaData loads from parent
  useEffect(() => {
    if (!quotaData?.limits) return
    const id = requestAnimationFrame(() => setLimits(quotaData.limits))
    return () => cancelAnimationFrame(id)
  }, [quotaData?.limits])

  const handleChange = (key: keyof QuotaLimits, value: string) => {
    const num = parseInt(value, 10)
    if (!isNaN(num) && num >= 0) setLimits((prev) => ({ ...prev, [key]: num }))
  }

  const handleSave = async () => {
    setSaving(true)
    try {
      const updated = await api.ai.quotas.update(limits)
      onSave(updated.limits)
      toast.success('Quota limits saved')
    } catch {
      toast.error('Failed to save quota limits')
    } finally {
      setSaving(false)
    }
  }

  if (!quotaData) return null

  return (
    <div className="rounded-lg border border-border bg-card p-4">
      <h2 className="mb-4 text-lg font-medium text-foreground">AI Daily Limits</h2>
      <div className="grid grid-cols-2 gap-3 sm:grid-cols-3">
        {FEATURE_LABELS.map(({ key, label }) => (
          <label key={key} className="block">
            <span className="mb-1 block text-sm font-medium text-foreground">{label}</span>
            <input
              type="number"
              min={0}
              value={limits[key]}
              onChange={(e) => handleChange(key, e.target.value)}
              className="w-full rounded-lg border border-border bg-input-background px-3 py-2 text-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </label>
        ))}
      </div>
      <button
        onClick={handleSave}
        disabled={saving}
        className="mt-4 flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:cursor-not-allowed disabled:opacity-50"
      >
        {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
        Save Limits
      </button>
    </div>
  )
}

import { useState } from 'react'
import { AlertTriangle, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { api } from '../../api/client'

interface ConfirmResetStepProps {
  onBack: () => void
}

export default function ConfirmResetStep({ onBack }: ConfirmResetStepProps) {
  const [confirmText, setConfirmText] = useState('')
  const [resetting, setResetting] = useState(false)

  const handleConfirmReset = async () => {
    if (confirmText !== 'RESET') return

    setResetting(true)
    try {
      await api.system.reset('RESET')
      toast.success('Database reset complete')
      window.location.href = '/'
    } catch (error) {
      console.error('Failed to reset database:', error)
      toast.error('Failed to reset database')
    } finally {
      setResetting(false)
    }
  }

  return (
    <>
      <div className="flex items-center gap-2 text-destructive">
        <AlertTriangle className="h-5 w-5" />
        <h3 className="text-lg font-medium">Confirm Reset</h3>
      </div>

      <div className="mt-4 space-y-4">
        <p className="text-sm text-foreground">
          Type{' '}
          <code className="rounded bg-muted px-1 font-mono">RESET</code>{' '}
          to confirm:
        </p>

        <input
          type="text"
          value={confirmText}
          onChange={(e) => setConfirmText(e.target.value)}
          placeholder="Type RESET"
          className="w-full rounded-lg border border-border bg-background px-3 py-2 font-mono text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
      </div>

      <div className="mt-6 flex justify-end gap-3">
        <button
          onClick={onBack}
          className="rounded-lg border border-border bg-background px-4 py-2 text-sm font-medium text-foreground transition-colors hover:bg-muted"
        >
          Back
        </button>
        <button
          onClick={handleConfirmReset}
          disabled={confirmText !== 'RESET' || resetting}
          className="flex items-center gap-2 rounded-lg bg-destructive px-4 py-2 text-sm font-medium text-destructive-foreground transition-colors hover:bg-destructive/90 disabled:cursor-not-allowed disabled:opacity-50"
        >
          {resetting && <Loader2 className="h-4 w-4 animate-spin" />}
          Reset Database
        </button>
      </div>
    </>
  )
}

import { useState } from 'react'
import { Trash2, AlertTriangle, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { api, type DeletionPreview } from '../../api/client'
import UserDeletionModal from './UserDeletionModal'

interface DeleteAccountSectionProps {
  /**
   * Kept for API stability / test compatibility; the passkey self-delete
   * endpoint infers the target profile from the authenticated session.
   * Legacy callers that passed a numeric id don't need to change.
   */
  profileId: number
  onDeleted: () => void
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars -- profileId kept for API stability
export default function DeleteAccountSection({ profileId: _profileId, onDeleted }: DeleteAccountSectionProps) {
  const [showModal, setShowModal] = useState(false)
  const [preview, setPreview] = useState<DeletionPreview | null>(null)
  const [loading, setLoading] = useState(false)
  const [deleting, setDeleting] = useState(false)

  const handleDeleteClick = async () => {
    setLoading(true)
    try {
      // Passkey-mode self-delete uses /auth/me/* which works under SessionAuth.
      // The /profiles/{id}/* equivalents are HomeOnlyAuth (404 in passkey) —
      // pre-v1.53.0 this silently failed ("Failed to load account info").
      const data = await api.auth.meDeletionPreview()
      setPreview(data)
      setShowModal(true)
    } catch {
      toast.error('Failed to load account info')
    } finally {
      setLoading(false)
    }
  }

  const handleConfirm = async () => {
    setDeleting(true)
    try {
      await api.auth.deleteMe()
      toast.success('Account deleted')
      onDeleted()
    } catch {
      toast.error('Failed to delete account')
      setDeleting(false)
    }
  }

  const handleCancel = () => {
    setShowModal(false)
    setPreview(null)
  }

  return (
    <div className="rounded-lg border border-destructive/30 bg-card p-4">
      <div className="flex items-center gap-2 text-destructive">
        <AlertTriangle className="h-5 w-5" />
        <h2 className="text-lg font-medium">Delete Account</h2>
      </div>
      <p className="mt-2 text-sm text-muted-foreground">
        Permanently delete your account and all associated data. This cannot be undone.
      </p>
      <button
        onClick={handleDeleteClick}
        disabled={loading}
        className="mt-4 flex items-center gap-2 rounded-lg bg-destructive px-4 py-2 text-sm font-medium text-destructive-foreground transition-colors hover:bg-destructive/90 disabled:cursor-not-allowed disabled:opacity-50"
      >
        {loading ? (
          <Loader2 className="h-4 w-4 animate-spin" />
        ) : (
          <Trash2 className="h-4 w-4" />
        )}
        Delete My Account
      </button>

      {showModal && preview && (
        <UserDeletionModal
          preview={preview}
          deleting={deleting}
          onConfirm={handleConfirm}
          onCancel={handleCancel}
        />
      )}
    </div>
  )
}

