function ProfileName({
  profile,
  onProfileUpdate,
  isCurrent,
}: {
  profile: ProfileWithStats
  onProfileUpdate: (id: number, changes: Partial<ProfileWithStats>) => void
  isCurrent: boolean
}) {
  const [editing, setEditing] = useState(false)
  const [name, setName] = useState(profile.name)

  const save = async () => {
    const trimmed = name.trim()
    if (!trimmed || trimmed === profile.name) { setEditing(false); return }
    try {
      const res = await api.profiles.rename(profile.id, trimmed)
      onProfileUpdate(profile.id, { name: res.name })
      toast.success('Profile renamed')
    } catch {
      toast.error('Failed to rename profile')
      setName(profile.name)
    }
    setEditing(false)
  }

  if (editing) {
    return (
      <div className="flex items-center gap-1">
        <input
          autoFocus
          aria-label="Profile name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          onBlur={save}
          onKeyDown={(e) => { if (e.key === 'Enter') save(); if (e.key === 'Escape') { setName(profile.name); setEditing(false) } }}
          className="w-32 rounded border border-border bg-input-background px-1.5 py-0.5 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-ring"
        />
        <button onClick={save} className="text-primary"><Check className="h-3.5 w-3.5" /></button>
        <button onClick={() => { setName(profile.name); setEditing(false) }} className="text-muted-foreground"><X className="h-3.5 w-3.5" /></button>
      </div>
    )
  }

  return (
    <div className="flex items-center gap-2">
      <span className="font-medium text-foreground">{profile.name}</span>
      {isCurrent && (
        <span className="rounded bg-primary/10 px-2 py-0.5 text-xs text-primary">Current</span>
      )}
      <button onClick={() => setEditing(true)} className="text-muted-foreground hover:text-foreground" title="Rename">
        <Pencil className="h-3.5 w-3.5" />
      </button>
    </div>
  )
}

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react'
import { api, AIStatus } from '../api/client'

interface AIStatusContextType {
  available: boolean
  configured: boolean
  valid: boolean
  error: string | null
  errorCode: string | null
  loading: boolean
  refresh: () => Promise<void>
  setFeatureQuotaExhausted: (feature: string) => void
  isFeatureAvailable: (feature: string) => boolean
}

const defaultStatus: AIStatusContextType = {
  available: false,
  configured: false,
  valid: false,
  error: null,
  errorCode: null,
  loading: true,
  refresh: async () => {},
  setFeatureQuotaExhausted: () => {},
  isFeatureAvailable: () => false,
}

const AIStatusContext = createContext<AIStatusContextType>(defaultStatus)

// eslint-disable-next-line react-refresh/only-export-components -- Hook is tightly coupled to provider
export function useAIStatus() {
  return useContext(AIStatusContext)
}

interface AIStatusProviderProps {
  children: ReactNode
}

export function AIStatusProvider({ children }: AIStatusProviderProps) {
  const [status, setStatus] = useState<Omit<AIStatusContextType, 'refresh' | 'loading' | 'setFeatureQuotaExhausted' | 'isFeatureAvailable'>>({
    available: false,
    configured: false,
    valid: false,
    error: null,
    errorCode: null,
  })
  const [loading, setLoading] = useState(true)
  const [quotaExhaustedFeatures, setQuotaExhaustedFeatures] = useState<Set<string>>(new Set())

  const setFeatureQuotaExhausted = useCallback((feature: string) => {
    setQuotaExhaustedFeatures(prev => new Set([...prev, feature]))
  }, [])

  const isFeatureAvailable = useCallback((feature: string): boolean => {
    return status.available && !quotaExhaustedFeatures.has(feature)
  }, [status.available, quotaExhaustedFeatures])

  const refresh = useCallback(async () => {
    try {
      const data: AIStatus = await api.ai.status()
      setStatus({
        available: data.available,
        configured: data.configured,
        valid: data.valid,
        error: data.error,
        errorCode: data.error_code,
      })
    } catch (error) {
      console.error('Failed to fetch AI status:', error)
      setStatus({
        available: false,
        configured: false,
        valid: false,
        error: 'Failed to check AI availability',
        errorCode: 'connection_error',
      })
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    let cancelled = false
    const doRefresh = async () => {
      try {
        const data: AIStatus = await api.ai.status()
        if (!cancelled) {
          setStatus({
            available: data.available,
            configured: data.configured,
            valid: data.valid,
            error: data.error,
            errorCode: data.error_code,
          })
        }
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to fetch AI status:', error)
          setStatus({
            available: false,
            configured: false,
            valid: false,
            error: 'Failed to check AI availability',
            errorCode: 'connection_error',
          })
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    }
    doRefresh()
    // Refresh every 5 minutes
    const interval = setInterval(doRefresh, 5 * 60 * 1000)
    return () => { cancelled = true; clearInterval(interval) }
  }, [])

  return (
    <AIStatusContext.Provider value={{ ...status, loading, refresh, setFeatureQuotaExhausted, isFeatureAvailable }}>
      {children}
    </AIStatusContext.Provider>
  )
}

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react'
import { api } from '../api/client'
import type { AuthProfile, PasskeyUser } from '../api/types'

interface AuthContextType {
  user: PasskeyUser | null
  profile: AuthProfile | null
  isLoading: boolean
  logout: () => Promise<void>
  refreshSession: () => Promise<void>
}

const AuthContext = createContext<AuthContextType | null>(null)

// eslint-disable-next-line react-refresh/only-export-components -- Hook is tightly coupled to provider
export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

// eslint-disable-next-line react-refresh/only-export-components -- Safe variant for mode-conditional usage
export function useOptionalAuth() {
  return useContext(AuthContext)
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<PasskeyUser | null>(null)
  const [profile, setProfile] = useState<AuthProfile | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  // Restore session on mount
  useEffect(() => {
    api.auth
      .me()
      .then((data) => {
        setUser(data.user)
        setProfile(data.profile)
      })
      .catch(() => {
        // Not logged in
      })
      .finally(() => setIsLoading(false))
  }, [])

  const refreshSession = useCallback(async () => {
    try {
      const data = await api.auth.me()
      setUser(data.user)
      setProfile(data.profile)
    } catch {
      setUser(null)
      setProfile(null)
    }
  }, [])

  const logout = useCallback(async () => {
    try {
      await api.auth.logout()
    } catch {
      // Ignore errors on logout
    }
    setUser(null)
    setProfile(null)
  }, [])

  return (
    <AuthContext.Provider
      value={{
        user,
        profile,
        isLoading,
        logout,
        refreshSession,
      }}
    >
      {children}
    </AuthContext.Provider>
  )
}

import { createContext, useContext, useCallback, ReactNode } from 'react'
import { api, type Profile, type RecipeDetail } from '../api/client'
import { useStoredProfile, saveProfileId, clearProfileId } from '../hooks/useStoredProfile'
import { useFavorites } from '../hooks/useFavorites'

interface ProfileContextType {
  profile: Profile | null
  theme: 'light' | 'dark'
  favoriteRecipeIds: Set<number>
  loading: boolean
  selectProfile: (profile: Profile) => Promise<void>
  logout: () => void
  toggleTheme: () => Promise<void>
  updateUnitPreference: (unit: 'metric' | 'imperial') => Promise<void>
  toggleFavorite: (recipe: RecipeDetail) => Promise<void>
  isFavorite: (recipeId: number) => boolean
}

const ProfileContext = createContext<ProfileContextType | null>(null)

// eslint-disable-next-line react-refresh/only-export-components -- Hook is tightly coupled to provider
export function useProfile() {
  const context = useContext(ProfileContext)
  if (!context) {
    throw new Error('useProfile must be used within a ProfileProvider')
  }
  return context
}

interface AuthProfile {
  id: number
  name: string
  avatar_color: string
  theme: string
  unit_preference: string
}

interface ProfileProviderProps {
  children: ReactNode
  authProfile?: AuthProfile | null
  onProfileSelected?: () => void
}

export function ProfileProvider({ children, authProfile, onProfileSelected }: ProfileProviderProps) {
  const { profile, setProfile, theme, setTheme, loading } = useStoredProfile(authProfile)
  const { favoriteRecipeIds, toggleFavorite, isFavorite, clearFavorites } = useFavorites(profile)

  const selectProfile = useCallback(async (selectedProfile: Profile) => {
    try {
      await api.profiles.select(selectedProfile.id)
      setProfile(selectedProfile)
      setTheme(selectedProfile.theme as 'light' | 'dark')
      saveProfileId(selectedProfile.id)
      // Re-check AI availability now that a session exists.  On first visit
      // after import the initial /api/ai/status call returns 401 (no session
      // yet); this ensures AI features are shown once the profile is active.
      onProfileSelected?.()
    } catch (error) {
      console.error('Failed to select profile:', error)
      throw error
    }
  }, [setProfile, setTheme, onProfileSelected])

  const logout = useCallback(() => {
    setProfile(null)
    clearFavorites()
    clearProfileId()
  }, [setProfile, clearFavorites])

  const toggleTheme = useCallback(async () => {
    if (!profile) return
    const newTheme = theme === 'light' ? 'dark' : 'light'
    setTheme(newTheme)
    try {
      // updatePreferences works in both home + passkey modes. The old PUT
      // /profiles/{id}/ returns 404 in passkey mode (HomeOnlyAuth), which
      // caused the toggle to flip dark → immediately flip back to light
      // when the caught error triggered the rollback below.
      const updated = await api.profiles.updatePreferences(profile.id, { theme: newTheme })
      setProfile(updated)
    } catch (error) {
      console.error('Failed to update theme:', error)
      setTheme(theme)
    }
  }, [profile, theme, setProfile, setTheme])

  const updateUnitPreference = useCallback(async (unit: 'metric' | 'imperial') => {
    if (!profile) return
    const previousUnit = profile.unit_preference
    setProfile({ ...profile, unit_preference: unit })
    try {
      const updated = await api.profiles.updatePreferences(profile.id, { unit_preference: unit })
      setProfile(updated)
    } catch (error) {
      console.error('Failed to update unit preference:', error)
      setProfile({ ...profile, unit_preference: previousUnit })
    }
  }, [profile, setProfile])

  return (
    <ProfileContext.Provider
      value={{
        profile, theme, favoriteRecipeIds, loading,
        selectProfile, logout, toggleTheme, updateUnitPreference,
        toggleFavorite, isFavorite,
      }}
    >
      {children}
    </ProfileContext.Provider>
  )
}

import { useState } from 'react'
import { toast } from 'sonner'
import { api, type AIStatus, type AIModel } from '../api/client'
import { useAIStatus } from '../contexts/AIStatusContext'

interface UseAPIKeyHandlersOptions {
  onAIStatusChange: (status: AIStatus) => void
  onModelsChange: (models: AIModel[]) => void
}

interface UseAPIKeyHandlersReturn {
  apiKey: string
  setApiKey: (key: string) => void
  testingKey: boolean
  savingKey: boolean
  handleTestApiKey: () => Promise<void>
  handleSaveApiKey: () => Promise<void>
}

export function useAPIKeyHandlers({
  onAIStatusChange,
  onModelsChange,
}: UseAPIKeyHandlersOptions): UseAPIKeyHandlersReturn {
  const globalAIStatus = useAIStatus()
  const [apiKey, setApiKey] = useState('')
  const [testingKey, setTestingKey] = useState(false)
  const [savingKey, setSavingKey] = useState(false)

  const handleTestApiKey = async () => {
    if (!apiKey.trim()) {
      toast.error('Please enter an API key')
      return
    }

    setTestingKey(true)
    try {
      const result = await api.ai.testApiKey(apiKey.trim())
      if (result.success) {
        toast.success(result.message)
      } else {
        toast.error(result.message)
      }
    } catch (error) {
      console.error('Failed to test API key:', error)
      toast.error('Failed to test API key')
    } finally {
      setTestingKey(false)
    }
  }

  const handleSaveApiKey = async () => {
    if (!apiKey.trim()) {
      toast.error('Please enter an API key')
      return
    }

    setSavingKey(true)
    try {
      const result = await api.ai.saveApiKey(apiKey.trim())
      if (result.success) {
        toast.success(result.message)
        setApiKey('')
        const statusData = await api.ai.status()
        onAIStatusChange(statusData)
        await globalAIStatus.refresh()
        const modelsData = await api.ai.models()
        onModelsChange(modelsData)
      } else {
        toast.error(result.message)
      }
    } catch (error) {
      console.error('Failed to save API key:', error)
      toast.error('Failed to save API key')
    } finally {
      setSavingKey(false)
    }
  }

  return {
    apiKey,
    setApiKey,
    testingKey,
    savingKey,
    handleTestApiKey,
    handleSaveApiKey,
  }
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { toast } from 'sonner'
import { api, type CollectionDetail, type Recipe } from '../api/client'

export function useCollectionData(collectionId: number) {
  const navigate = useNavigate()
  const [collection, setCollection] = useState<CollectionDetail | null>(null)
  const [loading, setLoading] = useState(true)
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
  const [deleting, setDeleting] = useState(false)

  useEffect(() => {
    if (!collectionId) return
    let cancelled = false
    ;(async () => {
      try {
        const data = await api.collections.get(collectionId)
        if (!cancelled) setCollection(data)
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load collection:', error)
          const msg = error instanceof Error ? error.message : null
          toast.error(msg || 'Failed to load collection')
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [collectionId])

  const handleRemoveRecipe = async (recipe: Recipe) => {
    if (!collection) return
    try {
      await api.collections.removeRecipe(collectionId, recipe.id)
      setCollection({
        ...collection,
        recipes: collection.recipes.filter((item) => item.recipe.id !== recipe.id),
      })
      toast.success('Removed from collection')
    } catch (error) {
      console.error('Failed to remove recipe:', error)
      const msg = error instanceof Error ? error.message : null
      toast.error(msg || 'Failed to remove recipe')
    }
  }

  const handleDeleteCollection = async () => {
    setDeleting(true)
    try {
      await api.collections.delete(collectionId)
      toast.success('Collection deleted')
      navigate('/collections')
    } catch (error) {
      console.error('Failed to delete collection:', error)
      const msg = error instanceof Error ? error.message : null
      toast.error(msg || 'Failed to delete collection')
    } finally {
      setDeleting(false)
    }
  }

  const handleRecipeClick = async (recipeId: number) => {
    try {
      await api.history.record(recipeId)
    } catch (error) {
      console.error('Failed to record history:', error)
    }
    navigate(`/recipe/${recipeId}`)
  }

  return {
    collection,
    loading,
    showDeleteConfirm,
    setShowDeleteConfirm,
    deleting,
    handleRemoveRecipe,
    handleDeleteCollection,
    handleRecipeClick,
  }
}

import { useState, useEffect } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { toast } from 'sonner'
import { api, type Collection } from '../api/client'

export function useCollectionsPage() {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const pendingRecipeId = searchParams.get('addRecipe')
    ? Number(searchParams.get('addRecipe'))
    : null

  const [collections, setCollections] = useState<Collection[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [newCollectionName, setNewCollectionName] = useState('')
  const [creating, setCreating] = useState(false)

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        const data = await api.collections.list()
        if (!cancelled) setCollections(data)
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load collections:', error)
          toast.error('Failed to load collections')
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [])

  const handleCreateCollection = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newCollectionName.trim()) return

    setCreating(true)
    try {
      const collection = await api.collections.create({
        name: newCollectionName.trim(),
      })
      setCollections([collection, ...collections])
      setNewCollectionName('')
      setShowCreateForm(false)
      toast.success('Collection created')

      if (pendingRecipeId) {
        try {
          await api.collections.addRecipe(collection.id, pendingRecipeId)
          toast.success('Recipe added to collection')
        } catch (error) {
          console.error('Failed to add recipe to collection:', error)
        }
        navigate(`/collection/${collection.id}`)
      }
    } catch (error) {
      console.error('Failed to create collection:', error)
      const msg = error instanceof Error ? error.message : null
      toast.error(msg || 'Failed to create collection')
    } finally {
      setCreating(false)
    }
  }

  const handleCollectionClick = async (collectionId: number) => {
    if (pendingRecipeId) {
      try {
        await api.collections.addRecipe(collectionId, pendingRecipeId)
        toast.success('Recipe added to collection')
      } catch (error: unknown) {
        const msg = error instanceof Error ? error.message : null
        toast.error(msg || 'Failed to add recipe to collection')
      }
    }
    navigate(`/collection/${collectionId}`)
  }

  const handleCancelCreate = () => {
    setShowCreateForm(false)
    setNewCollectionName('')
  }

  return {
    pendingRecipeId,
    collections,
    loading,
    showCreateForm,
    setShowCreateForm,
    newCollectionName,
    setNewCollectionName,
    creating,
    handleCreateCollection,
    handleCollectionClick,
    handleCancelCreate,
  }
}

import { useState, useRef, useEffect, useCallback } from 'react'
import { api, type DiscoverSuggestion } from '../api/client'
import { handleQuotaError } from '../lib/utils'
import { useAIStatus } from '../contexts/AIStatusContext'

interface UseDiscoverTabOptions {
  profileId: number | undefined
  aiAvailable: boolean
}

interface UseDiscoverTabResult {
  suggestions: DiscoverSuggestion[]
  loading: boolean
  error: boolean
  load: (refresh?: boolean) => void
  loadIfEmpty: () => void
}

export function useDiscoverTab({ profileId, aiAvailable }: UseDiscoverTabOptions): UseDiscoverTabResult {
  const { setFeatureQuotaExhausted } = useAIStatus()
  const [suggestions, setSuggestions] = useState<DiscoverSuggestion[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(false)
  const mountedRef = useRef(true)

  useEffect(() => {
    mountedRef.current = true
    return () => { mountedRef.current = false }
  }, [])

  const load = useCallback(async (refresh = false) => {
    if (!profileId) return
    setLoading(true)
    setError(false)
    try {
      const result = await api.ai.discover(profileId, refresh)
      if (!mountedRef.current) return
      setSuggestions(result.suggestions)
    } catch (err) {
      if (!mountedRef.current) return
      const isAbort =
        err instanceof Error &&
        (err.name === 'AbortError' || err.message.includes('abort'))
      if (isAbort) {
        console.debug('Discover fetch aborted:', err)
      } else if (handleQuotaError(err, 'Failed to load discover suggestions')) {
        setFeatureQuotaExhausted('discover')
      } else {
        setError(true)
      }
    } finally {
      if (mountedRef.current) {
        setLoading(false)
      }
    }
  }, [profileId, setFeatureQuotaExhausted])

  const loadIfEmpty = useCallback(() => {
    if (suggestions.length === 0 && !loading && !error && aiAvailable) {
      load()
    }
  }, [suggestions.length, loading, error, aiAvailable, load])

  return { suggestions, loading, error, load, loadIfEmpty }
}

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { toast } from 'sonner'
import { api, type Recipe, type Favorite, type HistoryItem } from '../api/client'

export function useHomeData() {
  const navigate = useNavigate()
  const [favorites, setFavorites] = useState<Favorite[]>([])
  const [history, setHistory] = useState<HistoryItem[]>([])
  const [recipesCount, setRecipesCount] = useState(0)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        const [favoritesData, historyData, recipesData] = await Promise.all([
          api.favorites.list(),
          api.history.list(6),
          api.recipes.list(1000),
        ])
        if (!cancelled) {
          setFavorites(favoritesData)
          setHistory(historyData)
          setRecipesCount(recipesData.length)
        }
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load data:', error)
          toast.error('Failed to load recipes')
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [])

  const favoriteIds = useMemo(
    () => new Set(favorites.map((f) => f.recipe.id)),
    [favorites]
  )

  const handleRecipeClick = useCallback(async (recipeId: number) => {
    try {
      await api.history.record(recipeId)
    } catch (error) {
      console.error('Failed to record history:', error)
    }
    navigate(`/recipe/${recipeId}`)
  }, [navigate])

  const handleToggleFavorite = useCallback(async (recipe: Recipe) => {
    const isFav = favoriteIds.has(recipe.id)
    try {
      if (isFav) {
        await api.favorites.remove(recipe.id)
        setFavorites((prev) => prev.filter((f) => f.recipe.id !== recipe.id))
        toast.success('Removed from favorites')
      } else {
        const newFav = await api.favorites.add(recipe.id)
        setFavorites((prev) => [...prev, newFav])
        toast.success('Added to favorites')
      }
    } catch (error) {
      console.error('Failed to toggle favorite:', error)
      toast.error(isFav ? 'Failed to remove from favorites' : 'Failed to add to favorites')
    }
  }, [favoriteIds])

  return {
    favorites,
    history,
    recipesCount,
    loading,
    favoriteIds,
    handleRecipeClick,
    handleToggleFavorite,
  }
}

import { useState, useEffect, useCallback } from 'react'
import { api } from '../api/client'
import type { PasskeyCredential } from '../api/types'
import {
  prepareRegistrationOptions,
  serializeRegistrationCredential,
} from '../lib/webauthn'

export default function usePasskeys() {
  const [credentials, setCredentials] = useState<PasskeyCredential[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [adding, setAdding] = useState(false)

  const loadCredentials = useCallback(async () => {
    try {
      const data = await api.passkey.listCredentials()
      setCredentials(data.credentials)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load passkeys')
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        const data = await api.passkey.listCredentials()
        if (!cancelled) setCredentials(data.credentials)
      } catch (err) {
        if (!cancelled) setError(err instanceof Error ? err.message : 'Failed to load passkeys')
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [])

  async function handleAdd() {
    setError('')
    setAdding(true)
    try {
      const options = await api.passkey.addCredentialOptions()
      const publicKeyOptions = prepareRegistrationOptions(options)
      const credential = await navigator.credentials.create({
        publicKey: publicKeyOptions,
      })
      if (!credential) {
        setError('Adding passkey was cancelled.')
        return
      }
      await api.passkey.addCredentialVerify(
        serializeRegistrationCredential(credential as PublicKeyCredential)
      )
      await loadCredentials()
    } catch (err) {
      if (err instanceof DOMException && err.name === 'NotAllowedError') {
        setError('Adding passkey was cancelled.')
      } else {
        setError(err instanceof Error ? err.message : 'Failed to add passkey')
      }
    } finally {
      setAdding(false)
    }
  }

  async function handleDelete(credentialId: number) {
    if (!window.confirm('Are you sure you want to delete this passkey? This cannot be undone.')) {
      return
    }
    setError('')
    try {
      await api.passkey.deleteCredential(credentialId)
      await loadCredentials()
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete passkey')
    }
  }

  return { credentials, loading, error, adding, handleAdd, handleDelete }
}

import { useState } from 'react'
import { toast } from 'sonner'
import { api, type ProfileWithStats, type DeletionPreview } from '../api/client'

interface UseProfileDeletionResult {
  showDeleteModal: boolean
  deletePreview: DeletionPreview | null
  deleting: boolean
  handleDeleteClick: (profileId: number) => Promise<void>
  handleConfirmDelete: () => Promise<void>
  handleCancelDelete: () => void
}

export function useProfileDeletion(
  profiles: ProfileWithStats[],
  onProfilesChange: (profiles: ProfileWithStats[]) => void
): UseProfileDeletionResult {
  const [showDeleteModal, setShowDeleteModal] = useState(false)
  const [deletePreview, setDeletePreview] = useState<DeletionPreview | null>(null)
  const [deletingId, setDeletingId] = useState<number | null>(null)
  const [deleting, setDeleting] = useState(false)

  const handleDeleteClick = async (profileId: number) => {
    try {
      const preview = await api.profiles.deletionPreview(profileId)
      setDeletePreview(preview)
      setDeletingId(profileId)
      setShowDeleteModal(true)
    } catch (error) {
      console.error('Failed to load deletion preview:', error)
      toast.error('Failed to load profile info')
    }
  }

  const handleConfirmDelete = async () => {
    if (!deletingId) return

    setDeleting(true)
    try {
      await api.profiles.delete(deletingId)
      onProfilesChange(profiles.filter((p) => p.id !== deletingId))
      toast.success('Profile deleted successfully')
      setShowDeleteModal(false)
      setDeletePreview(null)
      setDeletingId(null)
    } catch (error) {
      console.error('Failed to delete profile:', error)
      toast.error('Failed to delete profile')
    } finally {
      setDeleting(false)
    }
  }

  const handleCancelDelete = () => {
    setShowDeleteModal(false)
    setDeletePreview(null)
    setDeletingId(null)
  }

  return {
    showDeleteModal,
    deletePreview,
    deleting,
    handleDeleteClick,
    handleConfirmDelete,
    handleCancelDelete,
  }
}

import { useState, useEffect } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
