import { useState, useEffect, useRef } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { toast } from 'sonner'
import { api, type SearchResult } from '../api/client'

export interface UseSearchReturn {
  query: string
  searchInput: string
  setSearchInput: (value: string) => void
  results: SearchResult[]
  hasMore: boolean
  sites: Record<string, number>
  selectedSource: string | null
  setSelectedSource: (source: string | null) => void
  loading: boolean
  loadingMore: boolean
  importing: string | null
  handleSearchSubmit: (e: React.FormEvent) => void | Promise<void>
  handleLoadMore: () => void
  handleImport: (url: string) => Promise<void>
}

async function fetchSearchResults(
  query: string,
  selectedSource: string | null,
  pageNum: number,
  signal?: AbortSignal,
) {
  const sources = selectedSource || undefined
  return api.recipes.search(query, sources, pageNum, signal)
}

function isAbortError(error: unknown): boolean {
  return error instanceof DOMException && error.name === 'AbortError'
}

async function importRecipe(url: string) {
  const recipe = await api.recipes.scrape(url)
  await api.history.record(recipe.id)
  return recipe
}

function useSearchState(query: string) {
  const [searchInput, setSearchInput] = useState(query)
  const [results, setResults] = useState<SearchResult[]>([])
  const [, setTotal] = useState(0)
  const [page, setPage] = useState(1)
  const [hasMore, setHasMore] = useState(false)
  const [sites, setSites] = useState<Record<string, number>>({})
  const [selectedSource, setSelectedSource] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)
  const [loadingMore, setLoadingMore] = useState(false)
  const [importing, setImporting] = useState<string | null>(null)
  return { searchInput, setSearchInput, results, setResults, setTotal, page, setPage, hasMore, setHasMore, sites, setSites, selectedSource, setSelectedSource, loading, setLoading, loadingMore, setLoadingMore, importing, setImporting }
}

export function useSearch(): UseSearchReturn {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const query = searchParams.get('q') || ''
  const state = useSearchState(query)
  const { selectedSource, setSelectedSource, setResults, setSites, setTotal, setHasMore, setPage, setLoading, setLoadingMore, setImporting, setSearchInput } = state

  useEffect(() => {
    setSearchInput(query)
  }, [query, setSearchInput])

  const prevQueryRef = useRef(query)

  const applySearchResponse = (response: { results: SearchResult[]; sites: Record<string, number>; total: number; has_more: boolean }, pageNum: number, reset: boolean) => {
    if (reset) {
      setResults(response.results)
      setSites(response.sites)
    } else {
      setResults((prev) => [...prev, ...response.results])
    }
    setTotal(response.total)
    setHasMore(response.has_more)
    setPage(pageNum)
  }

  const searchRecipes = async (pageNum: number, reset: boolean = false, signal?: AbortSignal) => {
    try {
      const response = await fetchSearchResults(query, selectedSource, pageNum, signal)
      if (!signal?.aborted) applySearchResponse(response, pageNum, reset)
    } catch (error) {
      if (!signal?.aborted && !isAbortError(error)) {
        console.error('Search failed:', error)
        toast.error('Search failed. Please try again.')
      }
    } finally {
      if (!signal?.aborted) {
        setLoading(false)
        setLoadingMore(false)
      }
    }
  }

  useEffect(() => {
    if (!query) {
      navigate('/home')
      return
    }
    const abortController = new AbortController()
    setResults([])
    setPage(1)
    setSites({})
    setLoading(true)
    if (prevQueryRef.current !== query) {
      setSelectedSource(null)
      prevQueryRef.current = query
    }
    searchRecipes(1, true, abortController.signal)
    return () => { abortController.abort() }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- navigate and searchRecipes are stable, only re-run when query or filter changes
  }, [query, selectedSource])

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    const trimmed = state.searchInput.trim()
    if (!trimmed) return
    if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
      state.setImporting(trimmed)
      try {
        const recipe = await importRecipe(trimmed)
        toast.success(`Imported: ${recipe.title}`)
        navigate(`/recipe/${recipe.id}`)
      } catch (err) {
        const msg = err instanceof Error ? err.message : null
        toast.error(msg || 'Could not import recipe from that URL. Try a different link.')
      } finally {
        state.setImporting(null)
      }
      return
    }
    if (trimmed !== query) {
      navigate(`/search?q=${encodeURIComponent(trimmed)}`)
    }
  }

  const handleLoadMore = () => {
    setLoadingMore(true)
    searchRecipes(state.page + 1, false)
  }

  const handleImport = async (url: string) => {
    setImporting(url)
    try {
      const recipe = await importRecipe(url)
      toast.success(`Imported: ${recipe.title}`)
      navigate(`/recipe/${recipe.id}`)
    } catch (err) {
      const msg = err instanceof Error ? err.message : null
      toast.error(msg || 'Could not import recipe from that URL. Try a different link.')
    } finally { setImporting(null) }
  }

  return {
    query,
    searchInput: state.searchInput,
    setSearchInput: state.setSearchInput,
    results: state.results,
    hasMore: state.hasMore,
    sites: state.sites,
    selectedSource: state.selectedSource,
    setSelectedSource: state.setSelectedSource,
    loading: state.loading,
    loadingMore: state.loadingMore,
    importing: state.importing,
    handleSearchSubmit,
    handleLoadMore,
    handleImport,
  }
}

import { useState, useEffect } from 'react'
import { toast } from 'sonner'
import {
  api,
  type AIPrompt,
  type AIModel,
  type AIStatus,
  type Source,
  type ProfileWithStats,
  type QuotaResponse,
} from '../api/client'

export interface SettingsData {
  aiStatus: AIStatus | null
  prompts: AIPrompt[]
  models: AIModel[]
  sources: Source[]
  profiles: ProfileWithStats[]
  quotaData: QuotaResponse | null
  loading: boolean
  setAiStatus: (status: AIStatus | null) => void
  setPrompts: (prompts: AIPrompt[]) => void
  setModels: (models: AIModel[]) => void
  setSources: (sources: Source[]) => void
  setProfiles: (profiles: ProfileWithStats[]) => void
  setQuotaData: (data: QuotaResponse | null) => void
}

export function useSettingsData(isAdmin: boolean): SettingsData {
  const [aiStatus, setAiStatus] = useState<AIStatus | null>(null)
  const [prompts, setPrompts] = useState<AIPrompt[]>([])
  const [models, setModels] = useState<AIModel[]>([])
  const [sources, setSources] = useState<Source[]>([])
  const [profiles, setProfiles] = useState<ProfileWithStats[]>([])
  const [quotaData, setQuotaData] = useState<QuotaResponse | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        if (isAdmin) {
          const [statusData, promptsData, modelsData, sourcesData, profilesData] =
            await Promise.all([
              api.ai.status(),
              api.ai.prompts.list(),
              api.ai.models(),
              api.sources.list(),
              api.profiles.list(),
            ])
          if (!cancelled) {
            setAiStatus(statusData)
            setPrompts(promptsData)
            setModels(modelsData)
            setSources(sourcesData)
            setProfiles(profilesData)
          }
        }

        // Load quotas separately — 404 in home mode is expected
        try {
          const quotas = await api.ai.quotas.get()
          if (!cancelled) setQuotaData(quotas)
        } catch {
          // Quotas not available (e.g. home mode) — ignore
        }
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load settings:', error)
          toast.error('Failed to load settings')
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [isAdmin])

  return {
    aiStatus,
    prompts,
    models,
    sources,
    profiles,
    quotaData,
    loading,
    setAiStatus,
    setPrompts,
    setModels,
    setSources,
    setProfiles,
    setQuotaData,
  }
}

import { useState, useEffect, type Dispatch, type SetStateAction } from 'react'
import { api, type Profile } from '../api/client'

const PROFILE_STORAGE_KEY = 'cookie_selected_profile_id'

export function saveProfileId(id: number) {
  localStorage.setItem(PROFILE_STORAGE_KEY, String(id))
  document.cookie = `selected_profile_id=${id};path=/;SameSite=Lax`
}

export function clearProfileId() {
  localStorage.removeItem(PROFILE_STORAGE_KEY)
  document.cookie = 'selected_profile_id=;path=/;expires=Thu, 01 Jan 1970 00:00:00 GMT'
}

function getStoredProfileId(): number | null {
  const stored = localStorage.getItem(PROFILE_STORAGE_KEY)
  if (!stored) return null
  const id = parseInt(stored, 10)
  return isNaN(id) ? null : id
}

interface AuthProfile {
  id: number
  name: string
  avatar_color: string
  theme: string
  unit_preference: string
}

interface UseStoredProfileReturn {
  profile: Profile | null
  setProfile: Dispatch<SetStateAction<Profile | null>>
  theme: 'light' | 'dark'
  setTheme: Dispatch<SetStateAction<'light' | 'dark'>>
  loading: boolean
}

/**
 * Manages profile restoration from localStorage (home mode) or auth (passkey mode).
 * Applies the theme class to the document element.
 */
export function useStoredProfile(authProfile?: AuthProfile | null): UseStoredProfileReturn {
  const [profile, setProfile] = useState<Profile | null>(() =>
    authProfile ? (authProfile as Profile) : null
  )
  const [theme, setTheme] = useState<'light' | 'dark'>(() =>
    authProfile ? (authProfile.theme as 'light' | 'dark') : 'light'
  )
  const [loading, setLoading] = useState(authProfile === undefined)

  // Sync auth profile changes to state (passkey mode)
  useEffect(() => {
    if (authProfile === undefined) return
    const id = requestAnimationFrame(() => {
      if (authProfile) {
        setProfile(authProfile as Profile)
        setTheme(authProfile.theme as 'light' | 'dark')
      } else {
        setProfile(null)
      }
      setLoading(false)
    })
    return () => cancelAnimationFrame(id)
  }, [authProfile])

  // Apply theme class to document
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark')
    } else {
      document.documentElement.classList.remove('dark')
    }
  }, [theme])

  // Restore profile from localStorage (home mode only)
  useEffect(() => {
    if (authProfile !== undefined) return

    let cancelled = false
    ;(async () => {
      try {
        const storedId = getStoredProfileId()
        if (storedId) {
          try {
            const restored = await api.profiles.select(storedId)
            if (!cancelled) {
              setProfile(restored)
              setTheme(restored.theme as 'light' | 'dark')
            }
          } catch {
            clearProfileId()
          }
        }
      } catch (error) {
        console.error('Failed to restore session:', error)
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [authProfile])

  return { profile, setProfile, theme, setTheme, loading }
}

import { useState, useEffect, useRef, useCallback } from 'react'
import { createTimerTick, clearTimerInterval } from './timerUtils'

export interface Timer {
  id: string
  label: string
  duration: number // seconds
  remaining: number // seconds
  isRunning: boolean
}

export interface UseTimersReturn {
  timers: Timer[]
  addTimer: (label: string, duration: number, autoStart?: boolean) => string
  startTimer: (id: string) => void
  pauseTimer: (id: string) => void
  resetTimer: (id: string) => void
  deleteTimer: (id: string) => void
  toggleTimer: (id: string) => void
}

export function useTimers(onTimerComplete?: (timer: Timer) => void): UseTimersReturn {
  const [timers, setTimers] = useState<Timer[]>([])
  const intervalsRef = useRef<Map<string, number>>(new Map())
  const onCompleteRef = useRef(onTimerComplete)

  useEffect(() => {
    onCompleteRef.current = onTimerComplete
  }, [onTimerComplete])

  useEffect(() => {
    const intervals = intervalsRef.current
    return () => {
      intervals.forEach((intervalId) => clearInterval(intervalId))
    }
  }, [])

  const addTimer = useCallback((label: string, duration: number, autoStart: boolean = true): string => {
    const id = crypto.randomUUID()

    setTimers((prev) => [
      ...prev,
      { id, label, duration, remaining: duration, isRunning: autoStart },
    ])

    if (autoStart) {
      const tick = createTimerTick(id, intervalsRef, onCompleteRef, setTimers)
      const intervalId = window.setInterval(tick, 1000)
      intervalsRef.current.set(id, intervalId)
    }

    return id
  }, [])

  const startTimer = useCallback((id: string) => {
    clearTimerInterval(id, intervalsRef)

    const tick = createTimerTick(id, intervalsRef, onCompleteRef, setTimers)
    const intervalId = window.setInterval(tick, 1000)
    intervalsRef.current.set(id, intervalId)

    setTimers((prev) =>
      prev.map((timer) =>
        timer.id === id ? { ...timer, isRunning: true } : timer
      )
    )
  }, [])

  const pauseTimer = useCallback((id: string) => {
    clearTimerInterval(id, intervalsRef)
    setTimers((prev) =>
      prev.map((timer) =>
        timer.id === id ? { ...timer, isRunning: false } : timer
      )
    )
  }, [])

  const resetTimer = useCallback((id: string) => {
    clearTimerInterval(id, intervalsRef)
    setTimers((prev) =>
      prev.map((timer) =>
        timer.id === id
          ? { ...timer, remaining: timer.duration, isRunning: false }
          : timer
      )
    )
  }, [])

  const deleteTimer = useCallback((id: string) => {
    clearTimerInterval(id, intervalsRef)
    setTimers((prev) => prev.filter((timer) => timer.id !== id))
  }, [])

  const toggleTimer = useCallback(
    (id: string) => {
      const timer = timers.find((t) => t.id === id)
      if (!timer) return
      if (timer.isRunning) {
        pauseTimer(id)
      } else {
        startTimer(id)
      }
    },
    [timers, pauseTimer, startTimer]
  )

  return { timers, addTimer, startTimer, pauseTimer, resetTimer, deleteTimer, toggleTimer }
}

