export default function Home() {
  const navigate = useNavigate()
  const { profile } = useProfile()
  const aiStatus = useAIStatus()
  const [searchQuery, setSearchQuery] = useState('')
  const [importing, setImporting] = useState(false)
  const [activeTab, setActiveTab] = useState<Tab>('favorites')

  const { favorites, history, recipesCount, loading, favoriteIds, handleRecipeClick, handleToggleFavorite } = useHomeData()

  const discoverAvailable = aiStatus.isFeatureAvailable('discover')

  const discover = useDiscoverTab({
    profileId: profile?.id,
    aiAvailable: discoverAvailable,
  })

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    const trimmed = searchQuery.trim()
    if (!trimmed) return
    if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
      setImporting(true)
      try {
        const recipe = await api.recipes.scrape(trimmed)
        await api.history.record(recipe.id)
        toast.success(`Imported: ${recipe.title}`)
        navigate(`/recipe/${recipe.id}`)
      } catch (err) {
        const msg = err instanceof Error ? err.message : null
        toast.error(msg || 'Could not import recipe from that URL. Try a different link.')
      } finally {
        setImporting(false)
      }
      return
    }
    navigate(`/search?q=${encodeURIComponent(trimmed)}`)
  }

  const handleDiscoverTabClick = () => {
    setActiveTab('discover')
    discover.loadIfEmpty()
  }

  if (!profile) return null

  const showFavorites = activeTab === 'favorites' || !discoverAvailable

  return (
    <div className="flex min-h-screen flex-col bg-background">
      <NavHeader />
      <main className="flex-1 px-4 py-6">
        <div className="mx-auto max-w-4xl">
          <form onSubmit={handleSearchSubmit} className="mb-6">
            <div className="relative">
              <Search className="absolute left-4 top-1/2 h-5 w-5 -translate-y-1/2 text-muted-foreground" />
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search recipes or paste a URL..."
                disabled={importing}
                className="w-full rounded-xl border border-border bg-input-background py-3 pl-12 pr-4 text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring disabled:opacity-60"
              />
            </div>
          </form>

          {discoverAvailable && (
            <TabToggle
              activeTab={activeTab}
              onFavoritesClick={() => setActiveTab('favorites')}
              onDiscoverClick={handleDiscoverTabClick}
            />
          )}

          {loading ? (
            <RecipeGridSkeleton count={6} />
          ) : showFavorites ? (
            <FavoritesTab
              history={history}
              favorites={favorites}
              recipesCount={recipesCount}
              favoriteIds={favoriteIds}
              onRecipeClick={handleRecipeClick}
              onFavoriteToggle={handleToggleFavorite}
            />
          ) : (
            <DiscoverTab
              suggestions={discover.suggestions}
              loading={discover.loading}
              error={discover.error}
              aiAvailable={discoverAvailable}
              onRefresh={() => discover.load(true)}
              onRetry={() => discover.load()}
              onSwitchToFavorites={() => setActiveTab('favorites')}
            />
          )}
        </div>
      </main>
    </div>
  )
}

import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { api } from '../api/client'
import {
  prepareAuthenticationOptions,
  serializeAuthenticationCredential,
} from '../lib/webauthn'
import { useAuth } from '../contexts/AuthContext'

export default function PasskeyLogin() {
  const navigate = useNavigate()
  const { refreshSession } = useAuth()
  const [error, setError] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const webauthnSupported = typeof window !== 'undefined' && !!window.PublicKeyCredential

  async function handleLogin() {
    setError('')
    setSubmitting(true)

    try {
      const options = await api.passkey.loginOptions()

      if (options && 'no_credentials' in options) {
        setError('No accounts exist yet. Create an account first.')
        return
      }

      const publicKeyOptions = prepareAuthenticationOptions(options)

      const credential = await navigator.credentials.get({
        publicKey: publicKeyOptions,
      })

      if (!credential) {
        setError('Sign in was cancelled.')
        return
      }

      await api.passkey.loginVerify(
        serializeAuthenticationCredential(credential as PublicKeyCredential)
      )

      await refreshSession()
      navigate('/home')
    } catch (err) {
      if (err instanceof DOMException && err.name === 'NotAllowedError') {
        setError('Sign in was cancelled.')
      } else {
        setError(err instanceof Error ? err.message : 'Sign in failed')
      }
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-background p-4">
      <div className="w-full max-w-sm space-y-6">
        <div className="text-center">
          <h1 className="text-3xl font-bold text-foreground">Cookie</h1>
          <p className="mt-1 text-sm text-muted-foreground">Sign in with your passkey</p>
        </div>

        {error && (
          <div role="alert" className="rounded-md bg-red-50 p-3 text-sm text-red-800 dark:bg-red-900/20 dark:text-red-300">
            {error}
          </div>
        )}

        <div className="space-y-4">
          {webauthnSupported ? (
            <button
              onClick={handleLogin}
              disabled={submitting}
              className="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground shadow-sm hover:bg-primary/90 disabled:opacity-50"
            >
              {submitting ? 'Signing in...' : 'Sign In'}
            </button>
          ) : (
            <p className="text-center text-sm text-muted-foreground">
              Your browser does not support passkeys. Please use a modern browser or pair this device
              using a code from another device.
            </p>
          )}
        </div>

        <div className="text-center text-sm text-muted-foreground">
          <p>
            Don't have an account?{' '}
            <Link to="/register" className="font-medium text-primary hover:underline">
              Create Account
            </Link>
          </p>
        </div>

        <div className="text-center">
          <a href="/privacy/" className="text-xs text-muted-foreground hover:text-foreground hover:underline">
            Privacy Policy
          </a>
        </div>
      </div>
    </div>
  )
}

