export default function PlayMode() {
  const navigate = useNavigate()
  const { id } = useParams<{ id: string }>()
  const recipeId = Number(id)

  const { recipe, loading, aiAvailable } = usePlayModeData(recipeId)
  const [currentStep, setCurrentStep] = useState(0)
  const isLandscape = useIsLandscape()

  const handleTimerComplete = useTimerComplete()
  const timers = useTimers(handleTimerComplete)
  useWakeLock()
  useNotificationSetup()

  const instructions = getInstructions(recipe)
  const totalSteps = instructions.length
  const currentInstruction = instructions[currentStep] || ''
  const progress = totalSteps > 0 ? ((currentStep + 1) / totalSteps) * 100 : 0

  const handlePrevious = () => {
    if (currentStep > 0) setCurrentStep(currentStep - 1)
  }
  const handleNext = () => {
    if (currentStep < totalSteps - 1) setCurrentStep(currentStep + 1)
  }
  const handleExit = () => navigate(-1)

  useKeyboardNav(handlePrevious, handleNext, handleExit, currentStep, totalSteps)

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <LoadingSpinner className="min-h-screen" />
      </div>
    )
  }

  if (!recipe || totalSteps === 0) {
    return <PlayModeEmpty hasRecipe={!!recipe} onExit={handleExit} />
  }

  return (
    <div className="flex min-h-screen flex-col bg-background">
      <PlayModeHeader recipe={recipe} currentStep={currentStep} totalSteps={totalSteps} progress={progress} onExit={handleExit} />
      <div className={cn('flex min-h-0 flex-1 overflow-hidden', isLandscape ? 'flex-row' : 'flex-col')}>
        <div className={cn('flex flex-col', isLandscape ? 'min-w-0 flex-[3]' : 'flex-1')}>
          <InstructionDisplay currentStep={currentStep} currentInstruction={currentInstruction} />
          <PlayModeControls
            currentStep={currentStep}
            totalSteps={totalSteps}
            onPrevious={handlePrevious}
            onNext={handleNext}
          />
        </div>
        <TimerPanel timers={timers} instructionText={currentInstruction} aiAvailable={aiAvailable} isLandscape={isLandscape} />
      </div>
    </div>
  )
}

function useNotificationSetup() {
  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission()
    }
    unlockAudio()
  }, [])
}

function useKeyboardNav(
  onPrevious: () => void,
  onNext: () => void,
  onExit: () => void,
  currentStep: number,
  totalSteps: number,
) {
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') onPrevious()
      else if (e.key === 'ArrowRight' || e.key === 'ArrowDown') onNext()
      else if (e.key === 'Escape') onExit()
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
    // eslint-disable-next-line react-hooks/exhaustive-deps -- handlers use currentStep/totalSteps from closure, re-bind when they change
  }, [currentStep, totalSteps])
}

function PlayModeEmpty({ hasRecipe, onExit }: { hasRecipe: boolean; onExit: () => void }) {
  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-background p-4">
      <p className="mb-4 text-center text-muted-foreground">
        {hasRecipe ? 'No instructions available for this recipe.' : 'Recipe not found.'}
      </p>
      <button onClick={onExit} className="rounded-lg bg-primary px-4 py-2 text-primary-foreground">
        {hasRecipe ? 'Exit' : 'Go Back'}
      </button>
    </div>
  )
}

function getIsLandscape() {
  return typeof window !== 'undefined' && typeof window.matchMedia === 'function' && window.matchMedia('(orientation: landscape) and (min-width: 700px)').matches
}

function useIsLandscape() {
  const [isLandscape, setIsLandscape] = useState(getIsLandscape)
  useEffect(() => {
    if (typeof window.matchMedia !== 'function') return
    const mq = window.matchMedia('(orientation: landscape) and (min-width: 700px)')
    const handler = (e: MediaQueryListEvent) => setIsLandscape(e.matches)
    mq.addEventListener('change', handler)
    return () => mq.removeEventListener('change', handler)
  }, [])
  return isLandscape
}

function PlayModeHeader({
  recipe,
  currentStep,
  totalSteps,
  progress,
  onExit,
}: {
  recipe: RecipeDetail
  currentStep: number
  totalSteps: number
  progress: number
  onExit: () => void
}) {
  return (
    <div className="relative shrink-0 border-b border-border">
      <div className="h-1 bg-muted">
        <div className="h-full bg-primary transition-all duration-300" style={{ width: `${progress}%` }} />
      </div>
      <div className="flex items-center justify-between px-4 py-2.5">
        <div className="min-w-0 flex-1">
          <h1 className="line-clamp-1 text-sm font-semibold text-foreground">{recipe.title}</h1>
          <p className="text-xs text-muted-foreground">Step {currentStep + 1} of {totalSteps}</p>
        </div>
        <button onClick={onExit} className="ml-3 flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-muted text-muted-foreground transition-colors hover:bg-muted/80" aria-label="Exit play mode">
          <X className="h-5 w-5" />
        </button>
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { Plus } from 'lucide-react'
import { toast } from 'sonner'
import { api, type Profile, type ProfileInput } from '../api/client'
import { useProfile } from '../contexts/ProfileContext'
import CreateProfileForm, { PROFILE_COLORS } from '../components/CreateProfileForm'

export default function ProfileSelector() {
  const navigate = useNavigate()
  const { selectProfile } = useProfile()
  const [profiles, setProfiles] = useState<Profile[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [newName, setNewName] = useState('')
  const [selectedColor, setSelectedColor] = useState(PROFILE_COLORS[0])
  const [creating, setCreating] = useState(false)

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        const data = await api.profiles.list()
        if (!cancelled) setProfiles(data)
      } catch (error) {
        if (!cancelled) {
          console.error('Failed to load profiles:', error)
          toast.error('Failed to load profiles')
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()
    return () => { cancelled = true }
  }, [])

  const handleProfileSelect = async (profile: Profile) => {
    try {
      await selectProfile(profile)
      navigate('/home')
    } catch (error) {
      console.error('Failed to select profile:', error)
      toast.error('Failed to select profile')
    }
  }

  const handleCreateProfile = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newName.trim()) return
    setCreating(true)
    try {
      const data: ProfileInput = { name: newName.trim(), avatar_color: selectedColor, theme: 'light', unit_preference: 'metric' }
      const profile = await api.profiles.create(data)
      setProfiles([...profiles, profile])
      await selectProfile(profile)
      toast.success(`Welcome, ${profile.name}!`)
      navigate('/home')
    } catch (error) {
      console.error('Failed to create profile:', error)
      toast.error('Failed to create profile')
    } finally {
      setCreating(false)
    }
  }

  const handleCancelCreate = () => {
    setShowCreateForm(false)
    setNewName('')
    setSelectedColor(PROFILE_COLORS[0])
  }

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="text-muted-foreground">Loading...</div>
      </div>
    )
  }

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-background px-4">
      <div className="w-full max-w-md text-center">
        <h1 className="mb-2 text-4xl font-medium text-primary">Cookie</h1>
        <p className="mb-10 text-muted-foreground">Who's cooking today?</p>
        <ProfileGrid profiles={profiles} onSelect={handleProfileSelect} onAddClick={() => setShowCreateForm(true)} />
        {showCreateForm && (
          <CreateProfileForm newName={newName} onNameChange={setNewName} selectedColor={selectedColor} onColorChange={setSelectedColor} creating={creating} onSubmit={handleCreateProfile} onCancel={handleCancelCreate} />
        )}
      </div>
    </div>
  )
}

function ProfileGrid({ profiles, onSelect, onAddClick }: { profiles: Profile[]; onSelect: (p: Profile) => void; onAddClick: () => void }) {
  const getInitial = (name: string) => name.charAt(0).toUpperCase()
  return (
    <div className="mb-8 flex flex-wrap justify-center gap-6">
      {profiles.map((profile) => (
        <button key={profile.id} onClick={() => onSelect(profile)} className="group flex flex-col items-center gap-2">
          <div className="flex h-20 w-20 items-center justify-center rounded-full text-2xl font-medium text-white transition-transform group-hover:scale-105" style={{ backgroundColor: profile.avatar_color }}>
            {getInitial(profile.name)}
          </div>
          <span className="text-sm text-foreground">{profile.name}</span>
        </button>
      ))}
      <button onClick={onAddClick} className="group flex flex-col items-center gap-2">
        <div className="flex h-20 w-20 items-center justify-center rounded-full border-2 border-dashed border-muted-foreground/40 transition-colors group-hover:border-primary">
          <Plus className="h-8 w-8 text-muted-foreground/60 group-hover:text-primary" />
        </div>
        <span className="text-sm text-muted-foreground">Add Profile</span>
      </button>
    </div>
  )
}

