describe('useTimers', () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  it('adds timer and auto-starts by default', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test Timer', 300)
    })

    expect(result.current.timers).toHaveLength(1)
    expect(result.current.timers[0].label).toBe('Test Timer')
    expect(result.current.timers[0].duration).toBe(300)
    expect(result.current.timers[0].remaining).toBe(300)
    expect(result.current.timers[0].isRunning).toBe(true)
  })

  it('adds timer without auto-start when specified', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test Timer', 300, false)
    })

    expect(result.current.timers).toHaveLength(1)
    expect(result.current.timers[0].label).toBe('Test Timer')
    expect(result.current.timers[0].duration).toBe(300)
    expect(result.current.timers[0].remaining).toBe(300)
    expect(result.current.timers[0].isRunning).toBe(false)
  })

  it('returns timer id from addTimer', () => {
    const { result } = renderHook(() => useTimers())

    let timerId: string = ''
    act(() => {
      timerId = result.current.addTimer('Test Timer', 300)
    })

    expect(timerId).toBeTruthy()
    expect(result.current.timers[0].id).toBe(timerId)
  })

  it('starts and pauses timer', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test', 300, false)
    })

    const timerId = result.current.timers[0].id
    expect(result.current.timers[0].isRunning).toBe(false)

    act(() => {
      result.current.startTimer(timerId)
    })

    expect(result.current.timers[0].isRunning).toBe(true)

    act(() => {
      result.current.pauseTimer(timerId)
    })

    expect(result.current.timers[0].isRunning).toBe(false)
  })

  it('toggles timer state', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test', 300, false)
    })

    const timerId = result.current.timers[0].id
    expect(result.current.timers[0].isRunning).toBe(false)

    // Toggle on
    act(() => {
      result.current.toggleTimer(timerId)
    })
    expect(result.current.timers[0].isRunning).toBe(true)

    // Toggle off
    act(() => {
      result.current.toggleTimer(timerId)
    })
    expect(result.current.timers[0].isRunning).toBe(false)
  })

  it('resets timer to initial duration', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test', 300, false)
    })

    const timerId = result.current.timers[0].id

    // Start and advance time
    act(() => {
      result.current.startTimer(timerId)
    })

    act(() => {
      vi.advanceTimersByTime(5000)
    })

    expect(result.current.timers[0].remaining).toBe(295)

    // Reset
    act(() => {
      result.current.resetTimer(timerId)
    })

    expect(result.current.timers[0].remaining).toBe(300)
    expect(result.current.timers[0].isRunning).toBe(false)
  })

  it('deletes timer', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Timer 1', 300)
      result.current.addTimer('Timer 2', 600)
    })

    expect(result.current.timers).toHaveLength(2)

    const timerId = result.current.timers[0].id

    act(() => {
      result.current.deleteTimer(timerId)
    })

    expect(result.current.timers).toHaveLength(1)
    expect(result.current.timers[0].label).toBe('Timer 2')
  })

  it('decrements remaining time when running', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test', 10)
    })

    const timerId = result.current.timers[0].id

    act(() => {
      result.current.startTimer(timerId)
    })

    // Advance 5 seconds
    act(() => {
      vi.advanceTimersByTime(5000)
    })

    expect(result.current.timers[0].remaining).toBe(5)
  })

  it('calls onComplete when timer finishes', () => {
    const onComplete = vi.fn()
    const { result } = renderHook(() => useTimers(onComplete))

    act(() => {
      result.current.addTimer('Test', 3)
    })

    const timerId = result.current.timers[0].id

    act(() => {
      result.current.startTimer(timerId)
    })

    // Advance past completion
    act(() => {
      vi.advanceTimersByTime(4000)
    })

    expect(onComplete).toHaveBeenCalledTimes(1)
    expect(onComplete).toHaveBeenCalledWith(
      expect.objectContaining({
        label: 'Test',
        remaining: 0,
        isRunning: false,
      })
    )
  })

  it('stops timer at zero', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Test', 2)
    })

    const timerId = result.current.timers[0].id

    act(() => {
      result.current.startTimer(timerId)
    })

    act(() => {
      vi.advanceTimersByTime(5000)
    })

    expect(result.current.timers[0].remaining).toBe(0)
    expect(result.current.timers[0].isRunning).toBe(false)
  })

  it('supports multiple simultaneous timers', () => {
    const { result } = renderHook(() => useTimers())

    act(() => {
      result.current.addTimer('Timer 1', 100)
      result.current.addTimer('Timer 2', 200)
    })

    const timer1Id = result.current.timers[0].id
    const timer2Id = result.current.timers[1].id

    act(() => {
      result.current.startTimer(timer1Id)
      result.current.startTimer(timer2Id)
    })

    expect(result.current.timers[0].isRunning).toBe(true)
    expect(result.current.timers[1].isRunning).toBe(true)

    act(() => {
      vi.advanceTimersByTime(10000)
    })

    expect(result.current.timers[0].remaining).toBe(90)
    expect(result.current.timers[1].remaining).toBe(190)
  })
})

import { describe, it, expect } from 'vitest'
import { renderHook, act } from '@testing-library/react'
import { useAsync, useAsyncWithStaleData } from '../hooks/useAsync'

describe('useAsync', () => {
  it('starts with initial state', () => {
    const { result } = renderHook(() => useAsync<string>())

    expect(result.current.loading).toBe(false)
    expect(result.current.error).toBeNull()
    expect(result.current.data).toBeNull()
  })

  it('sets loading to true during execution', async () => {
    const { result } = renderHook(() => useAsync<string>())

    let resolvePromise: (value: string) => void
    const promise = new Promise<string>((resolve) => {
      resolvePromise = resolve
    })

    act(() => {
      result.current.execute(promise)
    })

    expect(result.current.loading).toBe(true)
    expect(result.current.error).toBeNull()
    expect(result.current.data).toBeNull()

    await act(async () => {
      resolvePromise('result')
    })
  })

  it('sets data on successful execution', async () => {
    const { result } = renderHook(() => useAsync<string>())

    await act(async () => {
      await result.current.execute(Promise.resolve('success'))
    })

    expect(result.current.loading).toBe(false)
    expect(result.current.error).toBeNull()
    expect(result.current.data).toBe('success')
  })

  it('sets error on failed execution', async () => {
    const { result } = renderHook(() => useAsync<string>())

    await act(async () => {
      try {
        await result.current.execute(Promise.reject(new Error('failed')))
      } catch {
        // Expected
      }
    })

    expect(result.current.loading).toBe(false)
    expect(result.current.error).toEqual(new Error('failed'))
    expect(result.current.data).toBeNull()
  })

  it('converts non-Error rejections to Error objects', async () => {
    const { result } = renderHook(() => useAsync<string>())

    await act(async () => {
      try {
        await result.current.execute(Promise.reject('string error'))
      } catch {
        // Expected
      }
    })

    expect(result.current.error).toBeInstanceOf(Error)
    expect(result.current.error?.message).toBe('string error')
  })

  it('rethrows the error from execute', async () => {
    const { result } = renderHook(() => useAsync<string>())

    await expect(
      act(async () => {
        await result.current.execute(Promise.reject(new Error('test error')))
      })
    ).rejects.toThrow('test error')
  })

  it('returns data from execute on success', async () => {
    const { result } = renderHook(() => useAsync<string>())

    let returnedData: string | undefined

    await act(async () => {
      returnedData = await result.current.execute(Promise.resolve('return value'))
    })

    expect(returnedData).toBe('return value')
  })

  it('clears previous data when starting new execution', async () => {
    const { result } = renderHook(() => useAsync<string>())

    // First execution
    await act(async () => {
      await result.current.execute(Promise.resolve('first'))
    })

    expect(result.current.data).toBe('first')

    // Start second execution
    let resolvePromise: (value: string) => void
    const promise = new Promise<string>((resolve) => {
      resolvePromise = resolve
    })

    act(() => {
      result.current.execute(promise)
    })

    // Data should be cleared during loading
    expect(result.current.data).toBeNull()

    await act(async () => {
      resolvePromise('second')
    })
  })

  it('clears previous error when starting new execution', async () => {
    const { result } = renderHook(() => useAsync<string>())

    // First execution fails
    await act(async () => {
      try {
        await result.current.execute(Promise.reject(new Error('failed')))
      } catch {
        // Expected
      }
    })

    expect(result.current.error).not.toBeNull()

    // Second execution starts
    let resolvePromise: (value: string) => void
    const promise = new Promise<string>((resolve) => {
      resolvePromise = resolve
    })

    act(() => {
      result.current.execute(promise)
    })

    // Error should be cleared during loading
    expect(result.current.error).toBeNull()

    await act(async () => {
      resolvePromise('success')
    })
  })

  it('reset() clears all state', async () => {
    const { result } = renderHook(() => useAsync<string>())

    // Execute successfully
    await act(async () => {
      await result.current.execute(Promise.resolve('data'))
    })

    expect(result.current.data).toBe('data')

    // Reset
    act(() => {
      result.current.reset()
    })

    expect(result.current.loading).toBe(false)
    expect(result.current.error).toBeNull()
    expect(result.current.data).toBeNull()
  })
})

describe('useAsyncWithStaleData', () => {
